
  CREATE TABLE "DIRKSPZM32"."ACS_ACCESS_POINTS_DEVICES" 
   (	"ACCESS_POINT_DEVICE_ID" VARCHAR2(32 CHAR) DEFAULT sys_guid() NOT NULL ENABLE, 
	"ACCESS_POINT_NAME" VARCHAR2(50 CHAR) NOT NULL ENABLE, 
	"ACCESS_POINT_DESCRIPTION" VARCHAR2(1000 CHAR), 
	"ACCESS_POINT_LOCATION" VARCHAR2(255 CHAR), 
	"ACCESS_DEVICE_NAME" VARCHAR2(50 CHAR) NOT NULL ENABLE, 
	"ACCESS_DEVICE_TYPE" VARCHAR2(50 CHAR) DEFAULT 'IR1000' NOT NULL ENABLE, 
	"ACCESS_DEVICE_TCP_HOSTNAME" VARCHAR2(255 CHAR) NOT NULL ENABLE, 
	"ACCESS_DEVICE_TCP_PORT" NUMBER(*,5) DEFAULT 8000 NOT NULL ENABLE, 
	"ACCESS_DEVICE_BUS_ADDRESS" NUMBER(*,0) DEFAULT 255 NOT NULL ENABLE, 
	"KEEP_OPEN_SEC" NUMBER(*,12) DEFAULT 5 NOT NULL ENABLE, 
	"ENABLED" VARCHAR2(1 CHAR) DEFAULT 'F' NOT NULL ENABLE
   ) ;
ALTER TABLE "DIRKSPZM32"."ACS_ACCESS_POINTS_DEVICES" ADD CONSTRAINT "CHK_ACCESS_DEVICE_BUS_ADDRESS" CHECK (ACCESS_DEVICE_BUS_ADDRESS is null or (ACCESS_DEVICE_BUS_ADDRESS >= 0 and ACCESS_DEVICE_BUS_ADDRESS <= 255)) DISABLE;
ALTER TABLE "DIRKSPZM32"."ACS_ACCESS_POINTS_DEVICES" ADD CONSTRAINT "CHK_ACCESS_DEVICE_TYPE" CHECK (ACCESS_DEVICE_TYPE in ('IR1000', 'ZKBOX', 'EVO43', 'pure.box')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ACS_ACCESS_POINTS_DEVICES" ADD CONSTRAINT "CHK_ENABLED" CHECK (ENABLED in ('T', 'F')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ACS_ACCESS_POINTS_DEVICES" ADD CONSTRAINT "PK_ACS_ACCESS_POINTS_DEVICES" PRIMARY KEY ("ACCESS_POINT_DEVICE_ID")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ACS_ACCESS_POINTS_DEVICES" ADD CONSTRAINT "UK_ACS_ACCESS_POINTS_DEVICES" UNIQUE ("ACCESS_POINT_NAME")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ACS_ACCESS_POINTS_DEVICES" ADD CONSTRAINT "UK_ACS_DEVICES_BUS_ADDRESS" UNIQUE ("ACCESS_DEVICE_TCP_HOSTNAME", "ACCESS_DEVICE_TCP_PORT", "ACCESS_DEVICE_BUS_ADDRESS")
  USING INDEX  ENABLE;


